var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엇!? 갑자기 아라크네가 공격을 멈췄어요!","JPN":"あっ！？　いきなりアラクネが攻撃を止めました！","ENG":"Huh?! The Arachne suddenly stopped attacking!","TWN":"嗯？！阿拉克涅突然停止攻擊咧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어서 피해요, 노엘!! 뭔가 이상해요!!","JPN":"早く逃げてください、ノエル！！　嫌な予感がします！","ENG":"Get out of there, Noelle!! Something's not right!","TWN":"快躲開，洛艾兒！！不太對勁！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이럴수가! 와일러 선수가 조종하는 아라크네가 갑자기 폭발해버렸다!","JPN":"そんなぁ！　ワイラー選手が操るアラクネがいきなり爆発しちゃった！","ENG":"What?! The Arachne that Wyler was controlling suddenly exploded!","TWN":"怎麼會這樣！瓦勒選手控制的阿拉克涅突然爆炸了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"과연 오작동일까? 그게 아니라면……!","JPN":"これは誤作動なのか？　それとも……！","ENG":"Is it a malfunction? Or could it be...!","TWN":"是操作錯誤嗎？還是……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아! 노엘 선수, 아무래도 대미지가 상당한 것 같은데!","JPN":"あっ！　ノエル選手、どうやら深刻なダメージを負った模様！","ENG":"Oh! Looks like it did a number on Noelle!","TWN":"糟糕！洛艾兒選手似乎傷得不輕！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■</color> 아니! 폭발하기 직전에 노엘이 있던 방향으로 뛰었잖아!\\n<color=#ffd34c>■■■</color> 아라크네 엄청 많이 남았어!\\n<color=#ffd34c>■■■</color> 저러다 진짜 누구 죽는 거 아니야?\\n<color=#ffd34c>■ ■</color> 근데 카운터 이기려면 저 정도는 해야지 ㅋㅋ\\n<color=#ffd34c>■ ■</color> 솔직히 펠리세트랑 라이카한테만 안 쓰면 문제없을 듯ㅋㅋ\\n<color=#ffd34c>■ ■</color> 다 죽여버리라고 건틀렛 살인마!!!","JPN":"<color=#ffd34c>■■</color> ちょっと！　爆発直前にノエルが居た方向に飛んだじゃない！\\n<color=#ffd34c>■■■</color> まだアラクネがいっぱいいる！\\n<color=#ffd34c>■■■</color> 本当に死人が出るんじゃない？\\n<color=#ffd34c>■ ■</color> でもカウンターに勝とうと思ったら、あれぐらいしないとダメだよなｗｗ\\n<color=#ffd34c>■ ■</color> ぶっちゃけフェリセットとライカにさえ使わなかったら許すｗｗ\\n<color=#ffd34c>■ ■</color> 全滅させちゃえ、ガントレット殺人鬼！","ENG":"<color=#ffd34c>■■</color> What? That thing just ran toward Noelle right before it exploded!\\n<color=#ffd34c>■■■</color> There are a lot more Arachnes left!\\n<color=#ffd34c>■■■</color> I think someone's gonna die at this rate!\\n<color=#ffd34c>■ ■</color> But you gotta do that much to beat a Counter, no? LOL!\\n<color=#ffd34c>■ ■</color> TBH, it'll be fine unless it's used against Félicette or Laika. HAHA!\\n<color=#ffd34c>■ ■</color> Kill them all, Gauntlet Murderer!!!","TWN":"<color=#ffd34c>■■</color> 故意的吧！根本是衝著洛艾兒去的！\\n<color=#ffd34c>■■■</color> 阿拉克涅的數量也太多！\\n<color=#ffd34c>■■■</color> 這樣下去真的會出人命吧？\\n<color=#ffd34c>■ ■</color> 不過要贏過制裁者只能這樣吧？呵呵\\n<color=#ffd34c>■ ■</color> 老實說只要不對費莉塞特和萊卡使用就沒問題，呵呵\\n<color=#ffd34c>■ ■</color> 根本是想大開殺戒吧，聖鎧殺人魔！！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으……!","JPN":"うう……！","ENG":"Urgh...!","TWN":"呃呃……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 일어설 수 있겠어요?","JPN":"ノエル、立てそうですか？","ENG":"Noelle, think can you get up?","TWN":"洛艾兒，你站得起來嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"고마워요. 펠리세트가 막아줘서 크게 다치지는 않았어요.","JPN":"ありがとうございます。フェリセットが防いでくれたおかげで致命傷は避けられました。","ENG":"Thanks, Félicette. If you didn't shield me, I would've been seriously injured.","TWN":"謝謝你費莉塞特，幸虧有你替我擋著，我才沒有傷得太嚴重。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만…….","JPN":"ですが……","ENG":"But still...","TWN":"只是……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"왜 그래? 시합 전에 그 기세는 어디로 갔지?","JPN":"どうした？　試合前のあの勢いはどこに行った？","ENG":"What's the matter? Where's the spirit you showed before the start of the match?","TWN":"怎麼了？比賽前的氣勢呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"설마 겨우 이 정도로 내 사랑을 막을 수 있을 거라고 생각했나?","JPN":"まさかこの程度で俺の愛を止められるとでも思ったのか？","ENG":"You think you can stop my love with that?","TWN":"你不會以為這樣就可以阻止我的愛吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"큭, 숫자가 너무 많아. 노엘도 당분간 움직일 수 없고.","JPN":"くっ、数が多すぎるわ。ノエルもしばらくは動けないし。","ENG":"Kgh, there are too many of them. And Noelle can't move for the time being.","TWN":"咳，數量太多了，而且洛艾兒也暫時無法行動，"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이대로는…….","JPN":"このままじゃ……","ENG":"At this rate...","TWN":"再這樣下去……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"흥, 이제 끝이다!","JPN":"ふん、これでおしまいだ！","ENG":"Hmph! It's over for you!","TWN":"哼，結束了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"응? 왜 갑자기 아라크네가 움직이지 않는 거지?","JPN":"うん？　急にアラクネが動かなくなった？","ENG":"Hmm? Why isn't the Arachne moving?","TWN":"嗯？阿拉克涅怎麼突然不動了？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"Can it be...","TWN":"難道……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"왜냐하면 전자전은 스태프로서 필수 소양이니까.","JPN":"電子戦はスタッフとしての基本素養なの。","ENG":"It's not moving because knowing how to deal with electronic warfare is essential for a staff member.","TWN":"電子戰是身為駕駛員的必備素養。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네가 손댄 아라크네들에게 재밍을 걸었어. 한동안 네 조작을 따르지 않을 거야.","JPN":"あなたが手を加えたアラクネたちにジャミングをかけたわ。しばらく命令は効かないはずよ。","ENG":"I jammed all your tampered Arachnes. You won't be able to control them for a while now.","TWN":"我在你的阿拉克涅上下干擾指令，阿拉克涅暫時不會聽從你的指令。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"아아, 스키너. 이제 슬슬 내 마음을 받아들일 때도 되지 않았나?","JPN":"ああ、スキナー。そろそろ俺の愛を受け入れてくれてもいいんじゃないか？","ENG":"Ahh, Skinner. Don't you think it's about time you accepted my love?","TWN":"啊啊，史金納，你差不多該接受我的心意了吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"어때? 지금이라도 나랑 손잡고 이 거지들을 끝장내는 거야.","JPN":"どうだ？　今からでも俺と手を取り合って、この貧乏人どもをぶっ潰すんだ。","ENG":"What do you say? You can join me, and we can crush these lowlifes for good.","TWN":"怎麼樣？現在還來得及，和我手牽手解決掉那些人吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"기분 나쁘니까 입 닥쳐, 와일러.","JPN":"気持ち悪いから黙って、ワイラー。","ENG":"You give me the creeps, so shut it, Wyler.","TWN":"給我閉嘴，瓦勒，你說的話讓我很想吐。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What did you say?","TWN":"你說什麼？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"날 좋아한다면서…… 멋대로 고백하고, 집착하고, 스토킹하더니 사람까지 죽였어.","JPN":"私を好きだと言いながら……勝手に告白して、執着して、ストーキングしただけじゃなくて、人も殺した。","ENG":"You say you like me... So you confess your feelings to me, become obsessed with me, stalk me, and eventually murder someone.","TWN":"你嘴上說喜歡我……但你只顧自地告白，不只糾纏我，甚至還跟蹤我，最後還殺了人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"스키너, 그건…… 다 너를 위해서였어.","JPN":"スキナー、それは……すべてお前のためだったんだ。","ENG":"Skinner, but that... was all for you.","TWN":"史金納，我做那些事……都是為了你！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"나는 네가 떨어뜨린 머리카락 한 올까지 지켜 줬다고. 지금도 내 방 벽장에 잘 간수해뒀단 말이야.","JPN":"俺はお前が落とした髪の毛一本さえも守ってあげたんだ。今も俺の部屋のクローゼットに大切にしまってある。","ENG":"I even saved the one strand of hair that fell out of your head. It's safely tucked away in my closet.","TWN":"我連你掉的一根頭髮都捨不得扔，它現在還好好地放在我房間的櫃子裡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어디가 날 위해서야! 너 자신을 위해서겠지!","JPN":"私のためだなんてふざけないで！　そんなのあなた自身のためでしかないわ！","ENG":"How's any of this for me?! It was always about you!","TWN":"什麼叫為了我！這都是為了你自己！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"한 번이라도 내 의견을 물어보긴 했어?","JPN":"一度でも私を意見を聞いてくれた？","ENG":"Have you ever cared to ask what I thought?","TWN":"你問過我的意見嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러지 말라고, 그만하라고 몇 번을 얘기해도 마찬가지였잖아.","JPN":"やめてって、もうやめてって何度言っても聞かなかったじゃない。","ENG":"I told you over and over to stop! But you never listened.","TWN":"我說了好多次叫你別這麼做，但你依舊故我。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네 눈에 나는 그냥 남들에게 뺏기기 싫은 인형 같은 거야.","JPN":"あなたにとって私は他人に取られたくない人形に過ぎないのよ。","ENG":"To you, I'm just another plaything that you don't want others to have.","TWN":"在你眼裡，我就只是一個你不想被別人搶走的娃娃而已。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"나는…… 아니, 우리는 무슨 수를 써서라도 너를 짓밟고 결승으로 올라갈 거야!","JPN":"私は……いいえ、私たちは、どんな手を使ってでもあなたを倒して決勝に進むわ！","ENG":"I... No, we are going to beat you and go to the finals no matter what!","TWN":"我……不，我們不管用什麼手段，都要打敗你進入決賽！"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그리고 너에게 제대로 된 죗값을 받게 하겠어.","JPN":"それから、あなたには罪を償わせてあげる。","ENG":"Then, I'm going to make you pay for your sins.","TWN":"然後讓你得到應有的懲罰。"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그게 내 각오야!","JPN":"それが私の覚悟よ！","ENG":"That's my determination!","TWN":"這就是我的決心！"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"……하! 하하하하!","JPN":"……ハッ！　アハハハッ！","ENG":"...Ha! HAHAHAHA!","TWN":"……哈！哈哈哈哈！"},"stage":{"bg":"GAUNTLET","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"흐하하하! 어처구니가 없어서 웃음이 다 나오는군!","JPN":"フハハハッ！　呆れて笑いしか出てこないぜ！","ENG":"Erhahaha! This is so ridiculous you're making me laugh!","TWN":"哈哈哈哈！太好笑了！"},"stage":{"bg":"GAUNTLET","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"스키너, 넌 속고 있는 거야. 네 주위를 어슬렁거리는 멍청한 년놈들에게.","JPN":"スキナー、お前は騙されているんだよ。お前の周りをうろつく、ろくでなしどもにだ。","ENG":"Skinner, you're being deceived. By those stupid morons around you.","TWN":"史金納，你被騙了，你周圍的人都在騙你。"},"stage":{"bg":"GAUNTLET","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"역시 전부 죽여 버려야 해. 그 속물들이 너를 더럽히고 있어.","JPN":"やっぱり全員殺しておかなくちゃな。あの俗物たちがお前を汚しているんだ。","ENG":"I'll just have to kill them all. Those idiots are defiling you.","TWN":"我要把那些人都殺了，那些傢伙都在給你洗腦。"},"stage":{"bg":"GAUNTLET","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그 수송선에서 얌전히 지켜보고 있어. 나의 스키너.","JPN":"その輸送船から大人しく見ていろ。俺のスキナー。","ENG":"You just sit tight in that transport aircraft and watch, my Skinner.","TWN":"我的史金納，你就在運輸機裡好好看著吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L32_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"마침 침식체들도 우리 편을 들어주고 있지.","JPN":"ちょうど侵食体どもも俺たちを味方してくれているしな。","ENG":"Even the C.O.s are on our side.","TWN":"剛好現在侵蝕體也站在我們這一邊。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"……정말 내 말은 하나도 안 듣는구나.","JPN":"……本当に私の話には聞く耳を持たないのね。","ENG":"...You really aren't listening to me, are you?","TWN":"……你真的是聽不懂人話。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"방금 전에 말했잖아, 와일러. 무슨 수를 써서라도 이길 거라고.","JPN":"今話したでしょ、ワイラー。どんな手を使ってでも勝つって。","ENG":"I just told you, Wyler. We're going to beat you no matter what.","TWN":"剛剛我已經說了，瓦勒。不管用什麼手段，我們都要打敗你。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"내가 왜 너랑 노닥거려 줬을 거라고 생각해?","JPN":"私が何であなたの相手をしてあげたと思う？","ENG":"Why do you think I'm even talking to you right now?","TWN":"你覺得我為什麼會在這邊跟你說這些？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"으음?","JPN":"むむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그럼, 정답 공개하겠습니다.","JPN":"では、正解をお見せします。","ENG":"And now, it's time to reveal the answer.","TWN":"那就揭曉答案囉。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참, 이 침식체들 귀찮게시리 치워도 치워도 끝이 없잖아?","JPN":"ったく侵食体どもめ、倒しても倒してもキリがねえ！","ENG":"Gah, there's no end to these bothersome C.O.s!","TWN":"真是的，這些侵蝕體好煩，怎麼殺都殺不完？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_04"},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이봐, 그쪽은 어때?","JPN":"おい、そっちはどう？","ENG":"Hey! How does it look on your end?","TWN":"喂，你那邊情況如何？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"말 시키지 마, 이쪽도 죽을 맛이거든?","JPN":"話かけなんな、こっちもやばいんだよ！","ENG":"Stop asking me! I'm busy here!","TWN":"別煩我，我這邊也很要命！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 기계 자식들 완전 맛탱이가 갔어!","JPN":"あの機械ども、完全におかしくなってる。","ENG":"Those machine dudes have gone completely crazy!","TWN":"那群機械跟瘋子一樣！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 적어도 이 침식체만 어떻게 싹 다 치워버릴 수만 있으면…… ","JPN":"ちっ、せめて侵食体を一気に片付けられたら…… ","ENG":"Tch, if only there was a way to get rid of the C.O.s...","TWN":"嘖，至少要把這些侵蝕體都處理掉……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야? 갑자기 뭐가 펑펑 터지는 거야?","JPN":"何だ？　この急な爆発は？","ENG":"What's that? Where's that exploding sound coming from?","TWN":"怎麼回事？好像有什麼東西突然爆炸？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어이, 금발! 너 거기 발밑에 거미가!","JPN":"おい、金髪！　お前の足元に蜘蛛が！","ENG":"Hey, blonde hair! There's a spider right under you!","TWN":"喂，金毛！你腳底下有蜘蛛！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으앗!","JPN":"うわっ！","ENG":"Whoa!","TWN":"啊啊！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 그 여자가 만든 지뢰잖아!","JPN":"こりゃ、あの女が作った地雷じゃねえか！","ENG":"That a mine made by that girl!","TWN":"這不是那個女人做的地雷嗎！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"포, 폭발한다!","JPN":"ば、爆発するぞ！","ENG":"I-it's gonna explode!","TWN":"要，爆了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"안심하세요, 그 지뢰들은 침식파를 추적하도록 세팅해놓았으니까요.","JPN":"ご安心ください、この地雷は侵食波を追うように設定されています。","ENG":"Don't worry. Those mines are calibrated to track Corruption rays.","TWN":"放心，我有設定好那些地雷只會追蹤侵蝕波。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"당신들에게서 침식파가 검출되지 않은 한, 폭발하지 않아요.","JPN":"あなたたちから侵食波でも検出されない限り、爆発はしません。","ENG":"As long as it doesn't detect any Corruption rays from you, it won't go off.","TWN":"只要你們身上沒有侵蝕波，地雷是不會爆炸的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아까 지하에서 해야 할 일이 있다고 한 게 설마 이거야?","JPN":"まさか、さっき地下に残ってやることがあるって言ったのは、これ？","ENG":"Is this what you meant by taking care of something down there?","TWN":"剛剛你說要留在地下道做的事就是這個？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사장님께선 저번 침식체의 습격을 받으신 뒤에 비슷한 일이 발생할 거라고 예측하셨거든요.","JPN":"社長は前回の侵食体からの襲撃以降、同じようなことが再び起きると予想されていました。","ENG":"After the last C.O. ambush, Boss predicted that something similar might happen again.","TWN":"上次被侵蝕體襲擊之後，老闆已經預料到會發生類似的事。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그래서 경기 전 날, 미리 지하 루트에 숨겨두었던 거미 지뢰를 회수할 필요가 있었습니다.","JPN":"そこで試合前日、あらかじめ地下ルートに隠しておいた蜘蛛型地雷を回収する必要があったのです。","ENG":"That's why I had to retrieve all my spider mines that I hid along the underground route the day before our match.","TWN":"所以必須在比賽前一天，提前收回藏在地下路線的蜘蛛地雷。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"엔트리 등록 시에는 포인트 제한 때문에 무장으로 들고 갈 수 가 없으니까요.","JPN":"エントリーにはポイント制限がありますから、武装して持っていくことはできなかったのです。","ENG":"For the entry registration, I couldn't take them with me because of the point limit.","TWN":"因為在登記選手名單時有點數限制，無法以武裝帶過去。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 사전에 등록되지 않는 무장 사용은 반칙이잖아?","JPN":"待てよ、事前に登録していない武器の使用は反則だろう？","ENG":"Wait, isn't using gear that wasn't registered beforehand cheating?","TWN":"等等，使用沒有事前登記的武裝是犯規吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요. 침식파가 검출되지 않는 한 폭발하지 않는다고.","JPN":"申し上げましたよね。侵食波が検出されない限り爆発はしません、と。","ENG":"Like I said, it won't explode unless it detects Corruption rays.","TWN":"我剛有說過，只要沒有檢測到侵蝕波就不會爆炸。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"뭐, 상대 측에서 침식체를 엔트리에 올려 놨다면 규칙 위반으로 실격하겠네요.","JPN":"まぁ、相手側が侵食体をエントリーメンバーに入れていたら、ルール違反で失格になっていたかもしれませんね。","ENG":"Well, if our opponent had put C.O.s on their rosters, we would be disqualified for breaking the rules.","TWN":"總之，如果對方將侵蝕體登記在名單上，那就會因違規而遭到淘汰。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"하, 하하하! 신난다! 펑펑 터지는데!","JPN":"はっ、ははは！　楽しいぜ！　ドカンドカンって！","ENG":"Ha, hahaha! How exciting! Explosions everywhere!","TWN":"哈，哈哈哈！好開心！都砰砰砰地爆炸咧！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L32_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"거미 형태의 지뢰라.","JPN":"蜘蛛の形をした地雷か。","ENG":"A mine shaped like a spider, eh?","TWN":"蜘蛛形態的地雷嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L33_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇군. 아직 살아있는 <color=#ffd34c>거미</color>가…… 그것도 현실 세계에 있었다니.","JPN":"そうか。まだ<color=#ffd34c>クモ</color>の生き残りがいたとは……しかも現実世界に。","ENG":"I see. So there's still an <color=#ffd34c>Arachnid</color> alive... even here on Normalside.","TWN":"原來如此，活生生的<color=#ffd34c>蜘蛛</color>……竟然就存在於現實世界。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이거 흥미로운데.","JPN":"これは興味深い。","ENG":"This is interesting.","TWN":"有意思喔。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};